CREATE TABLE USER_TEMPLATE(--     데이터가 입력될 때마다 겹치지 않는 무작위 고유 식별자(UUID)를 자동으로 생성해 소문자 문자열로 저장    user_template_id VARCHAR2(36) DEFAULT (LOWER(RAWTOHEX(SYS_GUID()))) PRIMARY KEY, -- 소유 고유 ID    user_id          VARCHAR2(36)                 NOT NULL,                          -- 유저 ID (FK)    template_id      RAW(16)                      NOT NULL,                          -- 템플릿 ID (FK)    created_at       DATE         DEFAULT SYSDATE NOT NULL,                          -- 생성 일시    -- 제약 조건 설정    --     존제하지 않는 템플릿이 등록되지 않게    CONSTRAINT fk_ut_temp FOREIGN KEY (template_id) REFERENCES template (template_id),    -- 한 유저가 같은 템플릿을 중복 소유하는 것을 방지 (선택 사항)    CONSTRAINT uq_user_temp UNIQUE (user_id, template_id));INSERT INTO user_template (user_id, template_id)VALUES ('현재_로그인된_유저_UUID', -- 여기에 실제 존재하는 유저 UUID를 넣으세요        (SELECT template_id FROM TEMPLATE WHERE name = '야경'));-- 예: 동일 유저가 '레트로' 템플릿도 수집함INSERT INTO user_template (user_id, template_id)VALUES ('현재_로그인된_유저_UUID',        (SELECT template_id FROM TEMPLATE WHERE name = '레트로'));SELECT *FROM USER_TEMPLATE;